class RedisSessionManager:
    """Manages user sessions stored in Redis."""

    def __init__(self, client, prefix=SESSION_PREFIX, expiry=SESSION_EXPIRY):
        self.client = client
        self.prefix = prefix
        self.expiry = expiry

    def _get_session_key(self, session_id):
        return f"{self.prefix}{session_id}"

    def create_session(self, user_data):
        """Create a new session and return the session ID."""
        session_id = str(uuid.uuid4())
        session_key = self._get_session_key(session_id)

        session_data = {
            "session_id": session_id,
            "user_data": json.dumps(user_data),
            "created_at": datetime.utcnow().isoformat(),
            "last_accessed": datetime.utcnow().isoformat(),
        }

        # Use SET with hash map for structured session data
        self.client.hset(session_key, mapping=session_data)
        self.client.expire(session_key, self.expiry)

        return session_id

    def get_session(self, session_id):
        """Retrieve session data by session ID."""
        session_key = self._get_session_key(session_id)
        session_data = self.client.hgetall(session_key)

        if not session_data:
            return None

        # Update last accessed time and refresh TTL
        self.client.hset(session_key, "last_accessed", datetime.utcnow().isoformat())
        self.client.expire(session_key, self.expiry)

        # Parse user_data from JSON
        session_data["user_data"] = json.loads(session_data["user_data"])
        return session_data

    def update_session(self, session_id, user_data):
        """Update session data."""
        session_key = self._get_session_key(session_id)

        if not self.client.exists(session_key):
            return False

        self.client.hset(session_key, "user_data", json.dumps(user_data))
        self.client.hset(session_key, "last_accessed", datetime.utcnow().isoformat())
        self.client.expire(session_key, self.expiry)

        return True

    def delete_session(self, session_id):
        """Delete a session."""
        session_key = self._get_session_key(session_id)
        return self.client.delete(session_key) > 0

    def set_session_value(self, session_id, key, value):
        """Set a specific key-value pair in the session using SET command."""
        simple_key = f"{self.prefix}{session_id}:{key}"
        self.client.set(simple_key, json.dumps(value), ex=self.expiry)

    def get_session_value(self, session_id, key):
        """Get a specific value from the session using GET command."""
        simple_key = f"{self.prefix}{session_id}:{key}"
        value = self.client.get(simple_key)
        if value:
            return json.loads(value)
        return None


