# ============================================================
# Caching Decorator
# ============================================================
def cache_result(ttl=CACHE_DEFAULT_TTL, key_prefix=""):
    """
    Decorator to cache expensive function results in Redis.
    
    Args:
        ttl: Time to live in seconds for the cached result.
        key_prefix: Optional prefix for the cache key.
    """
    def decorator(func):
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            # Generate a unique cache key based on function name and arguments
            cache_key_data = {
                "func": func.__qualname__,
                "args": str(args),
                "kwargs": str(sorted(kwargs.items())),
            }
            cache_key_hash = hashlib.md5(
                json.dumps(cache_key_data, sort_keys=True).encode()
            ).hexdigest()

            prefix = key_prefix or func.__qualname__
            cache_key = f"{CACHE_PREFIX}{prefix}:{cache_key_hash}"

            # Try to get cached result
            try:
                cached = redis_client.get(cache_key)
                if cached is not None:
                    cached_data = json.loads(cached)
                    app.logger.debug(f"Cache HIT for {cache_key}")
                    return cached_data["result"]
            except (redis.ConnectionError, json.JSONDecodeError) as e:
                app.logger.warning(f"Cache read error: {e}")

            # Execute the function
            start_time = time.time()
            result = func(*args, **kwargs)
            execution_time = time.time() - start_time

            # Store result in cache
            try:
                cache_data = {
                    "result": result,
                    "cached_at": datetime.utcnow().isoformat(),
                    "execution_time": execution_time,
                }
                redis_client.set(cache_key, json.dumps(cache_data), ex=ttl)
                app.logger.debug(
                    f"Cache MISS for {cache_key}, stored (exec: {execution_time:.4f}s)"
                )
            except (redis.ConnectionError, TypeError) as e:
                app.logger.warning(f"Cache write error: {e}")

            return result

        # Attach cache invalidation method
        def invalidate(*args, **kwargs):
            """Invalidate cache for specific arguments."""
            cache_key_data = {
                "func": func.__qualname__,
                "args": str(args),
                "kwargs": str(sorted(kwargs.items())),
            }
            cache_key_hash = hashlib.md5(
                json.dumps(cache_key_data, sort_keys=True).encode()
            ).hexdigest()
            prefix = key_prefix or func.__qualname__
            cache_key = f"{CACHE_PREFIX}{prefix}:{cache_key_hash}"
            redis_client.delete(cache_key)

        def invalidate_all():
            """Invalidate all cache entries for this function."""
            prefix = key_prefix or func.__qualname__
            pattern = f"{CACHE_PREFIX}{prefix}:*"
            keys = redis_client.keys(pattern)
            if keys:
                redis_client.delete(*keys)

        wrapper.invalidate = invalidate
        wrapper.invalidate_all = invalidate_all

        return wrapper
    return decorator


