# Cache Manager for manual cache operations
# ============================================================
class CacheManager:
    """Manual cache management for more control."""

    def __init__(self, client, prefix=CACHE_PREFIX):
        self.client = client
        self.prefix = prefix

    def set(self, key, value, ttl=CACHE_DEFAULT_TTL):
        """Set a cache value."""
        cache_key = f"{self.prefix}{key}"
        self.client.set(cache_key, json.dumps(value), ex=ttl)

    def get(self, key):
        """Get a cached value."""
        cache_key = f"{self.prefix}{key}"
        value = self.client.get(cache_key)
        if value:
            return json.loads(value)
        return None

    def delete(self, key):
        """Delete a cached value."""
        cache_key = f"{self.prefix}{key}"
        return self.client.delete(cache_key) > 0

    def clear_pattern(self, pattern):
        """Clear all keys matching a pattern."""
        full_pattern = f"{self.prefix}{pattern}"
        keys = self.client.keys(full_pattern)
        if keys:
            return self.client.delete(*keys)
        return 0

    def get_or_set(self, key, factory_func, ttl=CACHE_DEFAULT_TTL):
        """Get from cache or compute and store."""
        value = self.get(key)
        if value is not None:
            return value
        value = factory_func()
        self.set(key, value, ttl)
        return value


