# Routes - Rate Limiting (using Redis)
# ============================================================
def check_rate_limit(identifier, max_requests=100, window_seconds=60):
    """Simple sliding window rate limiter using Redis."""
    key = f"ratelimit:{identifier}"
    current = redis_client.get(key)

    if current is None:
        redis_client.set(key, 1, ex=window_seconds)
        return True, max_requests - 1

    current = int(current)
    if current >= max_requests:
        ttl = redis_client.ttl(key)
        return False, 0

    redis_client.incr(key)
    return True, max_requests - current - 1


@app.before_request
def rate_limit():
    """Apply rate limiting to all API routes."""
    if request.path.startswith("/api/"):
        identifier = request.remote_addr
        allowed, remaining = check_rate_limit(identifier, max_requests=100, window_seconds=60)

        if not allowed:
            return jsonify({
                "error": "Rate limit exceeded",
                "message": "Too many requests. Please try again later.",
            }), 429


