@app.route("/admin/cache/stats")
def cache_stats():
    """Get cache statistics."""
    try:
        info = redis_client.info()

        # Count cache keys
        cache_keys = redis_client.keys(f"{CACHE_PREFIX}*")
        session_keys = redis_client.keys(f"{SESSION_PREFIX}*")

        active_sessions = redis_client.get("stats:active_sessions") or "0"

        return jsonify({
            "cache": {
                "total_cache_keys": len(cache_keys),
                "total_session_keys": len(session_keys),
                "active_sessions": int(active_sessions),
            },
            "redis": {
                "used_memory": info.get("used_memory_human"),
                "connected_clients": info.get("connected_clients"),
                "total_commands_processed": info.get("total_commands_processed"),
                "keyspace_hits": info.get("keyspace_hits"),
                "keyspace_misses": info.get("keyspace_misses"),
                "hit_rate": (
                    round(
                        info.get("keyspace_hits", 0)
                        / max(info.get("keyspace_hits", 0) + info.get("keyspace_misses", 0), 1)
                        * 100,
                        2,
                    )
                ),
                "uptime_seconds": info.get("uptime_in_seconds"),
            },
        })
    except redis.ConnectionError:
        return jsonify({"error": "Redis not available"}), 503


@app.route("/admin/cache/clear", methods=["POST"])
def clear_cache():
    """Clear all cached data (not sessions)."""
    data = request.get_json() or {}
    target = data.get("target", "all")

    cleared = 0
    if target in ("all", "cache"):
        cache_keys = redis_client.keys(f"{CACHE_PREFIX}*")
        if cache_keys:
            cleared += redis_client.delete(*cache_keys)

    if target == "sessions":
        session_keys = redis_client.keys(f"{SESSION_PREFIX}*")
        if session_keys:
            cleared += redis_client.delete(*session_keys)
        redis_client.set("stats:active_sessions", 0)

    if target == "specific":
        func_name = data.get("function")
        if func_name:
            pattern = f"{CACHE_PREFIX}{func_name}:*"
            keys = redis_client.keys(pattern)
            if keys:
                cleared += redis_client.delete(*keys)

    return jsonify({
        "message": f"Cache cleared successfully",
        "target": target,
        "keys_removed": cleared,
    })


